import { useState, useEffect } from "react";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";

function WorkerManagement() {

const today = new Date().toISOString().split("T")[0];

const [workers,setWorkers] = useState([]);
const [projects,setProjects] = useState([]);
const [showForm,setShowForm] = useState(false);
const [editId,setEditId] = useState(null);

const [formData,setFormData] = useState({
name:"",
phone:"",
email:"",
role:"Labor",
type:"Full-Time Permanent",
project:"",
specialization:"",
experience:"",
address:"",
currentStatus:"Available",
description:"",
joined:today
});


// ================= FETCH WORKERS =================

useEffect(()=>{

fetch("http://localhost:5000/api")
.then(res=>res.json())
.then(data=>setWorkers(data));

},[]);


// ================= FETCH PROJECTS =================

useEffect(()=>{

fetch("http://localhost:5000/api/projects")
.then(res=>res.json())
.then(data=>setProjects(data))

},[])


// ================= INPUT CHANGE =================

const handleChange = (e)=>{

const {name,value} = e.target;

if(name==="phone"){
if(!/^\d{0,10}$/.test(value)) return;
}

setFormData({...formData,[name]:value});

};


// ================= SUBMIT =================

const handleSubmit = (e)=>{

e.preventDefault();

if(formData.phone.length !== 10){
alert("Phone number must be 10 digits");
return;
}

const apiUrl = editId
? `http://localhost:5000/api/${editId}`
: "http://localhost:5000/api";

const method = editId ? "PUT" : "POST";

fetch(apiUrl,{
method,
headers:{ "Content-Type":"application/json"},
body:JSON.stringify({
name:formData.name,
phone:formData.phone,
email:formData.email,
role:formData.role,
worker_type:formData.type,
assigned_project:formData.project,
specialization:formData.specialization,
experience:formData.experience,
address:formData.address,
current_status:formData.currentStatus,
description:formData.description,
joined:formData.joined
})
})
.then(res=>res.json())
.then(()=>{

window.location.reload();

});

};


// ================= DELETE =================

const handleDelete = (id)=>{

if(!window.confirm("Delete worker?")) return;

fetch(`http://localhost:5000/api/${id}`,{
method:"DELETE"
})
.then(()=>{

setWorkers(workers.filter(w=>w.id!==id));

});

};


// ================= EDIT =================

const handleEdit = (worker)=>{

setFormData({
name:worker.name,
phone:worker.phone,
email:worker.email,
role:worker.role,
type:worker.worker_type,
project:worker.assigned_project,
specialization:worker.specialization,
experience:worker.experience,
address:worker.address,
currentStatus:worker.current_status,
description:worker.description,
joined:worker.joined
});

setEditId(worker.id);
setShowForm(true);

};


// ================= STATS =================

const totalWorkers = workers.length;
const fullTime = workers.filter(w=>w.worker_type==="Full-Time Permanent").length;
const temporary = workers.filter(w=>w.worker_type==="Temporary").length;
const onSite = workers.filter(w=>w.current_status==="On Site").length;


return (

<div className="flex bg-gray-100 min-h-screen">

<Sidebar/>

<div className="flex-1 p-6">

<Topbar/>

{showForm ? (

<div className="bg-white rounded-xl shadow p-8 mt-6">

<h2 className="text-2xl font-semibold mb-6">
{editId ? "Edit Worker" : "Add New Worker"}
</h2>

<form onSubmit={handleSubmit} className="grid grid-cols-2 gap-6">


<input name="name" placeholder="Worker Name" value={formData.name} onChange={handleChange} className="border p-3 rounded"/>

<input name="phone" placeholder="Phone" value={formData.phone} onChange={handleChange} className="border p-3 rounded"/>

<input name="email" placeholder="Email" value={formData.email} onChange={handleChange} className="border p-3 rounded"/>


<select name="role" value={formData.role} onChange={handleChange} className="border p-3 rounded">
<option>Labor</option>
<option>Supervisor</option>
<option>Engineer</option>
</select>


<select name="type" value={formData.type} onChange={handleChange} className="border p-3 rounded">
<option>Full-Time Permanent</option>
<option>Temporary</option>
</select>


<select name="project" value={formData.project} onChange={handleChange} className="border p-3 rounded">

<option value="">Select Project</option>

{projects.map(p=>(
<option key={p.id}>{p.name}</option>
))}

</select>


<input name="specialization" placeholder="Specialization" value={formData.specialization} onChange={handleChange} className="border p-3 rounded"/>

<input name="experience" type="number" placeholder="Experience" value={formData.experience} onChange={handleChange} className="border p-3 rounded"/>


<input name="address" placeholder="Address" value={formData.address} onChange={handleChange} className="border p-3 rounded col-span-2"/>


<select name="currentStatus" value={formData.currentStatus} onChange={handleChange} className="border p-3 rounded">
<option>Available</option>
<option>On Site</option>
<option>On Leave</option>
</select>


<input type="date" name="joined" value={formData.joined} onChange={handleChange} className="border p-3 rounded"/>


<textarea name="description" value={formData.description} onChange={handleChange} className="border p-3 rounded col-span-2"/>


<button className="bg-orange-500 text-white px-6 py-2 rounded">
Save Worker
</button>

<button type="button" onClick={()=>setShowForm(false)} className="border px-6 py-2 rounded">
Cancel
</button>


</form>

</div>

) : (

<>

<div className="flex justify-between items-center mt-6">

<h1 className="text-3xl font-bold">Worker Management</h1>

<button
onClick={()=>setShowForm(true)}
className="bg-orange-500 text-white px-5 py-2 rounded"
>
+ Add Worker
</button>

</div>


<div className="grid grid-cols-4 gap-6 mt-6">

<Card title="Total Workers" value={totalWorkers}/>
<Card title="Full Time" value={fullTime}/>
<Card title="Temporary" value={temporary}/>
<Card title="On Site" value={onSite}/>

</div>


<div className="mt-6 bg-white rounded-xl shadow">

<table className="w-full">

<thead className="bg-gray-100">

<tr>
<th className="p-3">Name</th>
<th>Phone</th>
<th>Role</th>
<th>Project</th>
<th>Status</th>
<th>Actions</th>
</tr>

</thead>

<tbody>

{workers.map(w=>(

<tr key={w.id} className="border-t">

<td className="p-3">{w.name}</td>
<td>{w.phone}</td>
<td>{w.role}</td>
<td>{w.assigned_project}</td>
<td>{w.current_status}</td>

<td>

<button onClick={()=>handleEdit(w)} className="text-blue-600 mr-3">
Edit
</button>

<button onClick={()=>handleDelete(w.id)} className="text-red-600">
Delete
</button>

</td>

</tr>

))}

</tbody>

</table>

</div>

</>

)}

</div>

</div>

);

}

export default WorkerManagement;


function Card({title,value}){

return(
<div className="bg-white p-6 rounded-xl shadow">
<p className="text-gray-500">{title}</p>
<h2 className="text-3xl font-bold">{value}</h2>
</div>
)

}
